from itertools import product
class Solution:
    def countWinningSequences(self, s):
        MOD = 10 ** 9 + 7
        IDX = {'F': 0, 'W': 1, 'E': 2}
        beats = [[False, False, True], [True, False, False], [False, True, False]]
        n = len(s)
        alice = [IDX[c] for c in s]
        cnt = 0
        for combo in product(range(3), repeat=n):
            ok = True
            for i in range(1, n):
                if combo[i] == combo[i - 1]:
                    ok = False
                    break
            if not ok:
                continue
            diff = 0
            for i in range(n):
                bm, am = combo[i], alice[i]
                if bm == am:
                    continue
                elif beats[bm][am]:
                    diff += 1
                else:
                    diff -= 1
            if diff > 0:
                cnt += 1
        return cnt % MOD

