class Solution:
    def countWinningSequences(self, s):
        MOD = 10 ** 9 + 7
        IDX = {'F': 0, 'W': 1, 'E': 2}
        beats = [[False, False, True], [True, False, False], [False, True, False]]
        n = len(s)
        alice = [IDX[c] for c in s]
        OFFSET = n
        SIZE = 2 * n + 1
        dp = [[0] * SIZE for _ in range(3)]
        am0 = alice[0]
        for bm in range(3):
            if bm == am0:
                d = 0
            elif beats[bm][am0]:
                d = 1
            else:
                d = -1
            dp[bm][OFFSET + d] = (dp[bm][OFFSET + d] + 1) % MOD
        for i in range(1, n):
            am = alice[i]
            ndp = [[0] * SIZE for _ in range(3)]
            for prev in range(3):
                row = dp[prev]
                for idx in range(SIZE):
                    v = row[idx]
                    if v == 0:
                        continue
                    for bm in range(3):
                        if bm == prev:
                            continue
                        if bm == am:
                            d = 0
                        elif beats[bm][am]:
                            d = 1
                        else:
                            d = -1
                        nidx = idx + d
                        ndp[bm][nidx] = (ndp[bm][nidx] + v) % MOD
            dp = ndp
        total = 0
        for prev in range(3):
            for idx in range(OFFSET + 1, SIZE):
                total = (total + dp[prev][idx]) % MOD
        return total % MOD

