var countWinningSequences = function(s) {
    const MOD = 1000000007;
    const IDX = { F: 0, W: 1, E: 2 };
    const beats = [[false, false, true], [true, false, false], [false, true, false]];
    const n = s.length;
    const alice = Array.from(s).map(c => IDX[c]);
    const OFFSET = n;
    const SIZE = 2 * n + 1;
    let dp = [new Array(SIZE).fill(0), new Array(SIZE).fill(0), new Array(SIZE).fill(0)];
    const am0 = alice[0];
    for (let bm = 0; bm < 3; bm++) {
        let d;
        if (bm === am0) d = 0;
        else if (beats[bm][am0]) d = 1;
        else d = -1;
        dp[bm][OFFSET + d] = (dp[bm][OFFSET + d] + 1) % MOD;
    }
    for (let i = 1; i < n; i++) {
        const am = alice[i];
        const ndp = [new Array(SIZE).fill(0), new Array(SIZE).fill(0), new Array(SIZE).fill(0)];
        for (let prev = 0; prev < 3; prev++) {
            const row = dp[prev];
            for (let idx = 0; idx < SIZE; idx++) {
                const v = row[idx];
                if (v === 0) continue;
                for (let bm = 0; bm < 3; bm++) {
                    if (bm === prev) continue;
                    let d;
                    if (bm === am) d = 0;
                    else if (beats[bm][am]) d = 1;
                    else d = -1;
                    const nidx = idx + d;
                    ndp[bm][nidx] = (ndp[bm][nidx] + v) % MOD;
                }
            }
        }
        dp = ndp;
    }
    let total = 0;
    for (let prev = 0; prev < 3; prev++) {
        for (let idx = OFFSET + 1; idx < SIZE; idx++) {
            total = (total + dp[prev][idx]) % MOD;
        }
    }
    return total % MOD;
};
